import Link from '../Link'

const List = ({ header, contents }) => (
    <div className='work-link'>
        <h2>{header}</h2>
        <ul>
           {contents.map(({ link, title })=><Link link={link} title={title}/>)}
        </ul>
    </div>
)

export default List
